import numpy as np

# Define the fractional part function
def fractional_part(x):
    return x - np.floor(x)

# Define the function f(x)
def f(x):
    x_frac = fractional_part(x)
    if 0 <= x_frac < 0.5:
        return 2 * x_frac - 1
    elif 0.5 <= x_frac < 1:
        return 1 - 2 * x_frac
    else:
        raise ValueError("Unexpected fractional part")

# Check how many solutions there are for a given n
def count_solutions(n):
    solutions = set()
    for x in np.linspace(-100, 100, 100000):
        z = x * f(x)
        if np.isclose(f(z), x / n):
            solutions.add(x)
    return len(solutions)

# Find the smallest n such that there are at least 2012 solutions
n = 1
